fferLagThreshold":2000,"appId":"1111","cdnProvider":"ht","nextVideo":{"thumb":"https:\/\/ei.phncdn.com\/videos\/202012\/28\/379249702\/original\/(m=ecuKGgaaaa)(mh=IQ2qVjyOnTGqGL3G)14.jpg","duration":3696,"title":"BANG Surprise Podcast #5 With Carmela Clutch","isHD":1,"nextUrl":"\/view_video.php?viewkey=ph5fea3ec9b7c70","vkey":"ph5fea3ec9b7c70","isJoinPageEntry":false,"channelTitle":"Bang Casting","views":"559K","viewsText":"views","rating":69,"uploaderLink":"<a href=\"\/channels\/bang-casting\" class=\"bolded\">Bang Casting<\/a>","badge":"channel-icon"},"chromecast":true,"autoFullscreen":true};
