	translation='{"successTitle":"Thank you for flagging","successText":"If we find this content to be in violation of our <a href=\"https:\/\/www.pornhub.com\/information\/terms\">Terms of Service<\/a> we will remove it.","successButton":"Got it","btnCancel":"Cancel","btnSubmit":"Submit","btnNext":"Next","loginto":"If you have knowledge that the content violates our <a href=\"https:\/\/help.pornhub.com\/hc\/en-us\/articles\/4419869793683-Child-Sexual-Abuse-Material-Policy\" target=\"_blank\" rel=\"nofollow noopener\">CSAM policy<\/a> or <a href=\"https:\/\/help.pornhub.com\/hc\/en-us\/articles\/4419871787027-Non-Consensual-Content-Policy\" target=\"_blank\" rel=\"nofollow noopener\">NCC policy<\/a>, you may report it via our <a class=\"crrLink\" data-href=\"\/content-removal\" data-Flag-For=\"video\">Content Removal Request form<\/a>.","loginUrl":"\/login?redirect=B5dpAKl0R1rvf4QFTuT9mmKAggWbDXoaY2pkH9YIvwObYuKBuGCrIZnmcC8VLOLvY5rLxiFneXz1nXVS4gIGHSi2sIlz31Y9EzAVQkI50XbBOkgGSHMCQSSSzHI%3D","login":"Login","reason":"Tell us why","error":"Please provide reason","reasonBox":"Help us understand why you believe this content violates our terms of service or is otherwise objectionable by providing additional information\/detail(s).","reasonChannel":"Please provide URL and any additional information to help us locate and address the reason for flagging.","title":"Report this video","subtitle":"By reporting a piece of content that you think is inappropriate, you are helping to protect the Pornhub community as well as the integrity of our platform. Thank you! Reporting content is anonymous, so users cannot tell who made the report. Tell us why you would like to report this content:","desc":"Pornhub is a user-driven platform, whose objective is to provide a sex-positive environment for responsible users. \n            You may not approve of or like everything you see on Pornhub. That does not mean that the content is illegal<label for=\"readMoreState\" class=\"readMoreLabel\">... <span>Read more<\/span><\/label> <span class=\"readMoreDesc\">, or inappropriate. \n            If, however, you believe certain content is inappropriate, you can use the flagging feature to submit the content for review by our Pornhub staff. \n            All content that is reported through our flagging feature is reviewed to ensure it is not in violation of our <a href=\"\/information\/terms#terms\" rel=\"nofollow noopener\">Terms of Services<\/a>. \n            However, flagging something does not mean that it gets automatically removed. If the content does violate our <a href=\"\/information\/terms#terms\" rel=\"nofollow noopener\">Terms of Services<\/a>, \n            the content will be removed and the associated accounts could be permanently closed. For more information on our policies, how we enforce our policies, \n            and how to report content that you think may violate our <a href=\"\/information\/terms#terms\" rel=\"nofollow noopener\">Terms of Service<\/a>, please visit our <a href=\"https:\/\/help.pornhub.com\/hc\/en-us\/categories\/4419836212499\" target=\"_blank\" rel=\"nofollow noopener\">Trust and Safety page<\/a>.<\/span>","yes":"Yes","no":"No","confirmMessage":"Do you appear in this content or have first-hand knowledge that the content violates our <a href=\"https:\/\/help.pornhub.com\/hc\/en-us\/articles\/4419869793683\" target=\"_blank\" rel=\"nofollow noopener\">Child Sexual Abuse Material Policy<\/a>?","footer":"","moreInfoMessage":"For more information about how we process these requests, please click <a href=\"https:\/\/help.pornhub.com\/hc\/en-us\/articles\/4419875025043-Report-Harmful-Content\" target=\"_blank\" rel=\"nofollow noopener\">here<\/a>."}'
	flag-types='[{"key":"7","value":"Infringes My Rights or Other Legal Concern","tooltip":"This content otherwise invades your privacy (i.e. doxing, blackmail)","popup":"We are committed to protecting our community and the users of our platform. We have a zero-tolerance policy toward uploads that violate our <a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https:\/\/help.pornhub.com\/hc\/en-us\/articles\/4419871787027\">non-consensual content policy<\/a>,\n                    To have content that you have reason to believe invades your privacy, violates our <a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https:\/\/help.pornhub.com\/hc\/en-us\/articles\/4419871787027\">non-consensual content policy<\/a>, or is illegal, reviewed for removal,\n                    please complete and submit our <a href=\"\/content-removal\" rel=\"nofollow noopener\">CONTENT REMOVAL REQUEST FORM<\/a>. We treat content removal requests seriously and review all requests.","next":"\/content-removal"},{"key":"3","value":"Copyright Concern","tooltip":"This content infringes on your copyright","popup":"If you are a copyright owner and wish to report a copyright infringement, please complete and submit our <a href=\"\/information\/dmcaform\" rel=\"nofollow noopener\" class=\"js-reportLink\">DMCA takedown form<\/a>. \n                        Learn more about our copyright policy by visiting our DMCA page: <a href=\"\/information\/dmca\">www.pornhub.com\/information\/dmca<\/a>","next":"\/information\/dmcaform"},{"key":"2","value":"Potentially Features a Minor","tooltip":"For the purposes of our <a href=\"https:\/\/help.pornhub.com\/hc\/en-us\/articles\/4419869793683\" target=\"_blank\" rel=\"nofollow noopener\">policy on child sexual abuse material<\/a>, a minor is a person under 18 years of age.","popup":"We are committed to protecting our community and the users of our platform. We have a zero-tolerance policy toward uploads that violate our <a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https:\/\/help.pornhub.com\/hc\/en-us\/articles\/4419869793683\">child sexual abuse material (CSAM) policy<\/a>.\n            To have content that you have reason to believe violates our <a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https:\/\/help.pornhub.com\/hc\/en-us\/articles\/4419869793683\">CSAM policy<\/a> reviewed for removal, please complete and submit our\n            <a href=\"\/content-removal\" rel=\"nofollow noopener\">CONTENT REMOVAL REQUEST FORM<\/a>. We treat content removal requests seriously and review all requests. If you believe a user\u2019s profile violates this policy or is otherwise inappropriate, you can use the flagging feature to have the user\u2019s profile reviewed by Pornhub staff.","next":"\/content-removal"},{"key":"1","value":"Violent or Harmful Acts","tooltip":"The content features activity which poses a real threat or likelihood of causing serious physical injury or death to the individual(s) featured and\/or appears potentially non-consensual."},{"key":"6","value":"Hateful or Inflammatory","tooltip":"The content incites violence and\/or hatred against identifiable individuals and\/or groups of persons."},{"key":"5","value":"Spam or Misleading Content","tooltip":"Content that is massively posted or which serves to mislead users."},{"key":"4","value":"Otherwise Inappropriate or Objectionable","tooltip":"Content that you believe otherwise violates our <a href=\"\/information\/terms#terms\" rel=\"nofollow noopener\">terms of service<\/a>.","reason":"Help us understand why you believe this content violates our terms of service or is otherwise objectionable by providing additional information\/detail(s)."}]'
